UPDATE bed_record
SET del_flag = '1'
WHERE customer_id = #{id} AND bed_id = #{bedNumber}

UPDATE check_out_record
SET examing_by = #{userId},
status = #{status},
examing_date = #{date},
type = #{type}
WHERE check_out_record_id = #{id}

UPDATE bed_record
SET usage_end_date = #{date},
    history = #{number}
WHERE bed_record_id = #{id}

UPDATE outing_record
SET examing_by = #{userId},
status = #{status},
examing_date = #{date}
WHERE outing_record_id = #{id}
